import React, { useState } from "react";
import "./App.css";
import SOP from "./components/SOP"; // import Module 1 component

function App() {
  const [fileLoaded, setFileLoaded] = useState(false);
  const [fileName, setFileName] = useState("");
  const [selectedModule, setSelectedModule] = useState(null);

  const modules = [
    "SOP Data Acquisition & NPSV Processing Module",
    "SOP Signature Extraction Module (FFT-Based)",
    "Dataset Construction & Labeling Module",
    "OCSVM-Based Anomaly Detection Module",
    "DBSCAN-Based Unsupervised Detection Module",
    "Performance Evaluation & Metrics Module"
  ];

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setFileName(file.name);
      setFileLoaded(true);
    }
  };

  const goBack = () => {
    setSelectedModule(null);
  };

  return (
    <div className="container">

      <h1 className="title">
        Optical Fiber Security using SOP & Machine Learning
      </h1>

      {/* 🔹 Upload Section */}
      {!fileLoaded && (
        <div className="upload-box">
          <input type="file" onChange={handleFileUpload} />
          <p>Upload SOP Dataset (CSV)</p>
        </div>
      )}

      {/* 🔹 Module List */}
      {fileLoaded && !selectedModule && (
        <div className="modules-box">
          <h2>Dataset Loaded: {fileName}</h2>
          <h3>System Modules</h3>

          <ul>
            {modules.map((module, index) => (
              <li key={index}>
                <button
                  className="module-btn"
                  onClick={() => setSelectedModule(index)}
                >
                  {module}
                </button>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* 🔹 Module 1 UI */}
      {selectedModule === 0 && (
        <div>
          <button className="back-btn" onClick={goBack}>
            ⬅ Back
          </button>
          <SOP />
        </div>
      )}

      {/* 🔹 Other Modules Placeholder */}
      {selectedModule !== null && selectedModule !== 0 && (
        <div className="result-box">
          <button className="back-btn" onClick={goBack}>
            ⬅ Back
          </button>
          <h2>{modules[selectedModule]}</h2>
          <p>🚧 This module will be implemented next.</p>
        </div>
      )}

    </div>
  );
}

export default App;
